Here's an implementation of a stack data structure in Go:

```
package main

import (
	"fmt"
)

type Stack struct {
	items []int
}

func (s *Stack) Push(item int) {
	s.items = append(s.items, item)
}

func (s *Stack) Pop() int {
	if len(s.items) == 0 {
		return -1 // -1 could be returned as no element present or error message
	} else {
		popped := s.items[len(s.items)-1]
		s.items = s.items[:len(s.items)-1]
		return popped
	}
}

func (s *Stack) Peek() int {
	if len(s.items) == 0 {
		return -1 // -1 could be returned as no element present or error message 
	} else {
		return s.items[len(s.items)-1]
	}
}

func (s *Stack) IsEmpty() bool {
	return len(s.items) == 0
}

func main() {
	stack := Stack{}

	stack.Push(1)
	stack.Push(2)
	stack.Push(3)

	fmt.Println("Stack after pushing elements:", stack)

	fmt.Println("Popped element:", stack.Pop())
	fmt.Println("Stack after popping element:", stack)

	fmt.Println("Peek element:", stack.Peek())
	fmt.Println("Stack after peeking element:", stack)

	fmt.Println("Is stack empty:", stack.IsEmpty())
}
```

This implementation has a Stack struct with a slice of integers as its only property. It has four methods: Push, Pop, Peek, and IsEmpty.

The Push method appends a new item to the top of the stack. The Pop method removes the top item from the stack and returns it. The Peek method returns the top item from the stack without removing it. The IsEmpty method returns true if the stack is empty, and false otherwise.

